-- =============================================================================
-- Migration: Performance Indexes (Defensive)
-- Generated by: sql-hardener skill
-- Date: 2026-02-15
-- Updated: 2026-02-19 (Fully defensive - checks table/column existence)
-- =============================================================================
--
-- Creates supplementary indexes for performance optimization.
-- All operations check for table/column existence to prevent errors when
-- schema isn't fully synced (e.g., Prisma hasn't pushed yet).
-- =============================================================================

-- -----------------------------------------------------------------------------
-- 1. TIMESTAMP INDEXES (Critical for date-range queries)
-- -----------------------------------------------------------------------------

-- posts.published_at (DESC for "recent posts" queries)
DO $$
BEGIN
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema = 'public' AND table_name = 'posts' AND column_name = 'published_at')
  AND NOT EXISTS (SELECT 1 FROM pg_indexes WHERE schemaname = 'public' AND indexname = 'idx_posts_published_at')
  THEN
    CREATE INDEX idx_posts_published_at ON posts(published_at DESC NULLS LAST);
    RAISE NOTICE 'Created index idx_posts_published_at';
  END IF;
END $$;

-- posts.scheduled_at (for scheduler queries - partial index)
DO $$
BEGIN
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema = 'public' AND table_name = 'posts' AND column_name = 'scheduled_at')
  AND NOT EXISTS (SELECT 1 FROM pg_indexes WHERE schemaname = 'public' AND indexname = 'idx_posts_scheduled_at')
  THEN
    CREATE INDEX idx_posts_scheduled_at ON posts(scheduled_at) WHERE scheduled_at IS NOT NULL;
    RAISE NOTICE 'Created index idx_posts_scheduled_at';
  END IF;
END $$;

