-- calendar_posts partial index for pending/scheduled (most common query)
DO $$
BEGIN
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema = 'public' AND table_name = 'calendar_posts' AND column_name = 'scheduled_for')
  AND EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema = 'public' AND table_name = 'calendar_posts' AND column_name = 'status')
  AND NOT EXISTS (SELECT 1 FROM pg_indexes WHERE schemaname = 'public' AND indexname = 'idx_calendar_posts_pending')
  THEN
    CREATE INDEX idx_calendar_posts_pending ON calendar_posts(scheduled_for) WHERE status IN ('pending', 'scheduled');
    RAISE NOTICE 'Created index idx_calendar_posts_pending';
  END IF;
END $$;

-- -----------------------------------------------------------------------------
-- 3. COMPOSITE INDEXES (For common query patterns)
-- -----------------------------------------------------------------------------

-- Campaigns by user and status (dashboard query)
DO $$
BEGIN
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema = 'public' AND table_name = 'campaigns' AND column_name = 'user_id')
  AND EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema = 'public' AND table_name = 'campaigns' AND column_name = 'status')
  AND EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema = 'public' AND table_name = 'campaigns' AND column_name = 'created_at')
  AND NOT EXISTS (SELECT 1 FROM pg_indexes WHERE schemaname = 'public' AND indexname = 'idx_campaigns_user_status')
  THEN
    CREATE INDEX idx_campaigns_user_status ON campaigns(user_id, status, created_at DESC);
    RAISE NOTICE 'Created index idx_campaigns_user_status';
  END IF;
END $$;

-- Analytics by user, content, and date (reporting)
DO $$
BEGIN
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema = 'public' AND table_name = 'analytics_events' AND column_name = 'user_id')
  AND EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema = 'public' AND table_name = 'analytics_events' AND column_name = 'content_id')
  AND EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema = 'public' AND table_name = 'analytics_events' AND column_name = 'timestamp')
  AND NOT EXISTS (SELECT 1 FROM pg_indexes WHERE schemaname = 'public' AND indexname = 'idx_analytics_events_user_content_date')
  THEN
    CREATE INDEX idx_analytics_events_user_content_date ON analytics_events(user_id, content_id, timestamp DESC);
    RAISE NOTICE 'Created index idx_analytics_events_user_content_date';
  END IF;
END $$;

-- Platform connections active lookup
DO $$
BEGIN
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema = 'public' AND table_name = 'platform_connections' AND column_name = 'user_id')
  AND EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema = 'public' AND table_name = 'platform_connections' AND column_name = 'platform')
  AND EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema = 'public' AND table_name = 'platform_connections' AND column_name = 'is_active')
  AND NOT EXISTS (SELECT 1 FROM pg_indexes WHERE schemaname = 'public' AND indexname = 'idx_platform_connections_active')
  THEN
    CREATE INDEX idx_platform_connections_active ON platform_connections(user_id, platform) WHERE is_active = true;
    RAISE NOTICE 'Created index idx_platform_connections_active';
  END IF;
END $$;

