-- -----------------------------------------------------------------------------
-- 5. ANALYZE TABLES (Only if they exist)
-- -----------------------------------------------------------------------------

DO $$
DECLARE
  tables TEXT[] := ARRAY['users', 'personas', 'posts', 'campaigns', 'calendar_posts',
                         'analytics_events', 'platform_connections', 'api_usage', 'notifications'];
  t TEXT;
BEGIN
  FOREACH t IN ARRAY tables LOOP
    IF EXISTS (SELECT 1 FROM information_schema.tables WHERE table_schema = 'public' AND table_name = t) THEN
      EXECUTE format('ANALYZE %I', t);
      RAISE NOTICE 'Analyzed table %', t;
    END IF;
  END LOOP;
END $$;
